import { useState, useEffect, useCallback } from 'react';
import { getClientes, createCliente, updateCliente, deleteCliente, exportClientes } from '../services/api';
import { BRL, fDate, maskPhone, STATUS_COLORS, TIPO_LABEL, blurBRL } from '../utils/format';
import { useToast } from '../context/ToastContext';

const BLANK = {
  nome:'', data_venda:'', celular:'', nascimento:'', email:'', endereco:'', profissao:'',
  tipo:'consorcio', administradora:'', cota:'', grupo:'',
  valor_credito:'', prazo:'', parcela:'',
  status:'ativo', observacoes:''
};

export default function Clientes() {
  const toast = useToast();
  const [list, setList] = useState([]);
  const [search, setSearch] = useState('');

  const load = useCallback(async (q = '') => {
    try { setList(await getClientes(q)); }
    catch (err) { toast(err.message, 'err'); }
  }, [toast]);

  useEffect(() => { load(); }, [load]);

  async function handleImport(file) {
    const texto = await file.text();
    const linhas = texto.split("\n");

    for (let i = 1; i < linhas.length; i++) {
      const col = linhas[i].split(",");

      if (!col[0]) continue;

      try {
        await createCliente({
          nome: col[0],
          data_venda: col[1],
          celular: col[2],
          nascimento: col[3],
          endereco: col[4],
          profissao: col[5],
          tipo: col[6],
          administradora: col[7],
          cota: col[8],
          grupo: col[9],
          valor_credito: parseFloat(col[10]) || 0,
          prazo: parseInt(col[11]) || 0,
          parcela: parseFloat(col[12]) || 0,
          status: col[13] || "ativo",
          email: col[14],
          observacoes: col[15]
        });
      } catch (e) {
        console.log("Erro linha:", i);
      }
    }

    toast("Importação concluída 🚀");
    load();
  }

  async function handleExport() {
    await exportClientes();
  }

  return (
    <div style={{ padding: 20 }}>
      <h2>Clientes</h2>

      <div style={{ marginBottom: 20 }}>
        <label style={{
          padding: "10px 15px",
          background: "#444",
          color: "#fff",
          borderRadius: 6,
          cursor: "pointer",
          marginRight: 10
        }}>
          📤 Importar CSV
          <input
            type="file"
            accept=".csv"
            style={{ display: "none" }}
            onChange={(e) => {
              if (e.target.files[0]) handleImport(e.target.files[0]);
            }}
          />
        </label>

        <button onClick={handleExport}>
          📥 Exportar
        </button>
      </div>

      {list.map((c) => (
        <div key={c.id} style={{
          background: "#222",
          padding: 10,
          marginBottom: 8,
          borderRadius: 6
        }}>
          <strong>{c.nome}</strong> | {c.celular} | {BRL(c.valor_credito)}
        </div>
      ))}
    </div>
  );
}
